const body = $json.body || {};
const candidates = [
  body.url,
  body.website_url,
  body.website,
  body.source_url,
  $json.url,
  $json.website_url,
  $json.website,
  $json.source_url,
  typeof body === 'string' ? body : '',
  typeof $json === 'string' ? $json : ''
];

let inputUrl = candidates
  .find(value => typeof value === 'string' && value.trim())
  ?.trim() || '';

if (!inputUrl && body && typeof body === 'object') {
  const nested = body.body || body.data || body.payload;
  if (nested && typeof nested === 'object') {
    inputUrl = String(nested.url || nested.website_url || nested.website || nested.source_url || '').trim();
  }
}

if (!inputUrl) {
  return [{
    json: {
      success: false,
      statusCode: 400,
      error: 'Missing required field: url',
      received_keys: Object.keys($json || {}),
      body_keys: body && typeof body === 'object' ? Object.keys(body) : []
    }
  }];
}

inputUrl = inputUrl
  .replace(/^['\"]|['\"]$/g, '')
  .replace(/[\u200B-\u200D\uFEFF]/g, '')
  .trim();

let parsed;
try {
  parsed = new URL(/^https?:\/\//i.test(inputUrl) ? inputUrl : `https://${inputUrl}`);
  if (!parsed.hostname || !parsed.hostname.includes('.')) {
    throw new Error('URL hostname must include a dot');
  }
} catch (error) {
  return [{
    json: {
      success: false,
      statusCode: 400,
      error: 'Invalid URL',
      received_url: inputUrl,
      detail: error.message
    }
  }];
}

const source_url = parsed.href.replace(/\/$/, '');
const website_id = parsed.hostname
  .replace(/^www\./i, '')
  .replace(/[^a-zA-Z0-9]+/g, '-')
  .replace(/^-|-$/g, '')
  .toLowerCase();

return [{ json: { success: true, source_url, website_id } }];

const source_url = $('Normalize Request').first().json.source_url;
const website_id = $('Normalize Request').first().json.website_id;
const source = new URL(source_url);
const origin = source.origin;
const rawUrls = Array.isArray($json.urls) ? $json.urls : [];
const urls = new Set();
const priorityPaths = ['', '/', '/about', '/about-us', '/services', '/products', '/pricing', '/contact', '/contact-us', '/faq'];

for (const path of priorityPaths) {
  urls.add(new URL(path, origin).href.replace(/\/$/, ''));
}

for (const rawUrl of rawUrls) {
  if (!rawUrl || /^(mailto:|tel:|javascript:)/i.test(rawUrl)) continue;
  try {
    const url = new URL(rawUrl, origin);
    const sameDomain = url.hostname.replace(/^www\./i, '') === source.hostname.replace(/^www\./i, '');
    if (!sameDomain || !url.protocol.startsWith('http')) continue;
    url.hash = '';
    url.search = '';
    urls.add(url.href.replace(/\/$/, ''));
  } catch (error) {}
}

return [{
  json: {
    website_id,
    source_url,
    urls: Array.from(urls).slice(0, 20),
    max_pages: 20
  }
}];

const website_id = $('Build Crawl Request').first().json.website_id;
const pages = Array.isArray($json.pages) ? $json.pages : [];

return pages
  .filter(page => page && typeof page.markdown === 'string' && page.markdown.trim().length >= 150)
  .map(page => ({
    json: {
      text: page.markdown.trim(),
      metadata: {
        website_id,
        url: page.url
      }
    }
  }));

const website_id = $('Build Crawl Request').first().json.website_id;
const pages = Array.isArray($json.pages) ? $json.pages : [];
const successful = pages.filter(page => page && typeof page.markdown === 'string' && page.markdown.trim().length >= 50);
const text_length = successful.reduce((sum, page) => sum + page.markdown.trim().length, 0);

if (successful.length === 0 || text_length < 50) {
  return [{
    json: {
      success: false,
      website_id,
      pages_checked: pages.length,
      successful_pages: 0,
      text_length,
      error: 'The crawl-api did not return enough readable markdown for this website. Check the Crawl Pages node output for failed or empty_content pages.'
    }
  }];
}

return [{
  json: {
    success: true,
    website_id,
    pages_checked: pages.length,
    pages_indexed: successful.length,
    text_length,
    chatbot_url: `https://website-bot-frontend-1klt.onrender.com/${website_id}/chat`
  }
}];
